import javax.naming.Context;
import javax.naming.InitialContext;
import javax.naming.NamingException;
import javax.naming.directory.Attribute;
import javax.naming.directory.Attributes;
import javax.naming.directory.DirContext;
import javax.naming.directory.InitialDirContext;
import javax.naming.directory.SearchControls;
import javax.naming.directory.SearchResult;

public class LDAPUserSearch {

    public static Map<String, String> searchLDAPUser(String username, String ldapUrl, String ldapUserDN, String ldapPassword) {
        try {
            Properties env = new Properties();
            env.put(Context.INITIAL_CONTEXT_FACTORY, "com.sun.jndi.ldap.LdapCtxFactory");
            env.put(Context.PROVIDER_URL, ldapUrl);
            env.put(Context.SECURITY_AUTHENTICATION, "simple");
            env.put(Context.SECURITY_PRINCIPAL, ldapUserDN);
            env.put(Context.SECURITY_CREDENTIALS, ldapPassword);

            DirContext ctx = new InitialDirContext(env);
            SearchControls controls = new SearchControls();
            controls.setSearchScope(SearchControls.SUBTREE_SCOPE);

            String searchFilter = "(&(objectClass=person)(uid=" + username + "))";
            String[] attributes = {"mail", "cn", "departmentNumber"};
            Attributes attributesObject = ctx.getAttributes(searchFilter, attributes);
            Attribute attribute = attributesObject.get("mail");
            String email = (attribute != null) ? attribute.get().toString() : "";

            attribute = attributesObject.get("cn");
            String fullName = (attribute != null) ? attribute.get().toString() : "";
            attribute = attributesObject.get("departmentNumber");
            String department = (attribute != null) ? attribute.get().toString() : "";

            Map<String, String> result = new HashMap<>();
            result.put("email", email);
            result.put("fullName", fullName);
            result.put("department", department);

            return result;
        } catch (NamingException e) {
            System.out.println(e.getMessage());
            throw new RuntimeException(e);
        }
    }

    public static void main(String[] args) {
        String username = "your_username";
        String ldapUrl = "ldap://your_ldap_url:389/";
        String ldapUserDN = "your_ldap_user_dn";
        String ldapPassword = "your_ldap_password";

        Map<String, String> userAttributes = searchLDAPUser(username, ldapUrl, ldapUserDN, ldapPassword);
        System.out.println(userAttributes);
    }
}